import{_ as o,o as t,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"99. Professional Development Leave","description":"","frontmatter":{"title":"99. Professional Development Leave","eba":"Mental Health Services 2024-2028","topics":["leave","education-pd"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/education-pd/99-professional-development-leave.md","filePath":"ebas/mental-health/rpn-pen-mho/education-pd/99-professional-development-leave.md"}'),r={name:"ebas/mental-health/rpn-pen-mho/education-pd/99-professional-development-leave.md"};function s(i,e,l,p,d,m){return t(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="_99-professional-development-leave" tabindex="-1">99. Professional Development Leave <a class="header-anchor" href="#_99-professional-development-leave" aria-label="Permalink to &quot;99. Professional Development Leave&quot;">​</a></h1><p>Other than subclause 99.8 , this clause does not apply to casual Employees.</p><p><strong>99.1</strong> Professional Development Leave</p><p><strong>(a)</strong> All Nurses must meet the continuing professional development (CPD) standards of the Nursing and Midwifery Board of Australia.</p><p><strong>(b)</strong> CPD means activities that maintain knowledge in the Employee&#39;s current area of practice, improve and broaden their knowledge, expertise and competence, and develop the personal and professional qualities required through their professional lives. The CPD cycle involves:</p><p><strong>(i)</strong> reviewing practice</p><p><strong>(ii)</strong> identifying learning needs</p><p><strong>(iii)</strong> planning and participating in relevant learning activities; and</p><p><strong>(iv)</strong> reflecting on the value of those activities.</p><p><strong>(c)</strong> Professional development leave may be utilised:</p><p><strong>(i)</strong> to undertake CPD as defined at 99.1(b) and/or</p><p><strong>(ii)</strong> to attend nursing or health related conferences, seminars or workshops; and/or</p><p><strong>(iii)</strong> for activities including research or home study; and/or</p><p><strong>(iv)</strong> to support State Government initiatives to improve workforce development of priority areas of nursing and health care.</p><p><strong>99.2</strong> Amount of professional development leave</p><p><strong>(a)</strong> Full-time Employees are entitled to five days&#39; paid professional development leave (as defined in subclause 99.1.</p><p><strong>(b)</strong> Part-time Employees who work a minimum of three shifts per week are entitled to five days&#39; paid professional development leave (as defined in subclause 99.1. All other part-time Employees are entitled to two days paid professional leave.</p><p><strong>(c)</strong> An Employee who is a Nurse Practitioner will be entitled to a further 10 hours of paid professional development leave per annum.</p><p><strong>(d)</strong> Other than in accordance with sub-clause 99.2(e)below, professional development leave does not accumulate from year to year.</p><p><strong>(e)</strong> Employees may access all or part of a subsequent year’s entitlement during one year. The entitlement for the subsequent year will reduce accordingly.</p><p><strong>99.3</strong> Payment A day for the purposes of professional development leave is the Employee&#39;s usual shift length. For example, a night shift worker who takes professional development leave for a 10-hour night shift is entitled to 10 hours payment.</p><p><strong>99.4</strong> Application Professional development leave is available only on written application by the Employee. An Employee must apply in writing to the Employer at least six weeks prior to the proposed professional development leave date. If the professional</p><p>development leave is to undertake home study, the Employee&#39;s application will detail the relevance of the study to the Employee&#39;s employment.</p><p><strong>99.5</strong> Response to application</p><p><strong>(a)</strong> An application for professional development leave will be approved by the Employer unless there are exceptional circumstances that justify non-approval.</p><p><strong>(b)</strong> The Employer must notify the Employee in writing whether the leave request is approved within seven days.</p><p><strong>(c)</strong> If the leave is not approved, the reasons will be included in the notification to the Employee.</p><p><strong>(d)</strong> The use of professional development leave is at the sole discretion of the Employee and except for the conditions in this clause, no other conditions attach to the granting of professional development leave.</p><p><strong>99.6</strong> Leave not granted Where a valid application is made for professional/study leave (in whole or part) but no leave is granted during the calendar year, one day&#39;s leave will be added to the Employee&#39;s accrued annual leave or taken in another manner as mutually agreed between the Employer and the Employee.</p><p><strong>99.7</strong> Where leave occurs on a rostered day off Professional development leave need not take place on a day that the Employee would otherwise work. In those circumstances the Employer will do one of the following:</p><p><strong>(a)</strong> allocation of a day’s professional development leave paid at the ordinary rate of pay; or</p><p><strong>(b)</strong> time off in lieu on a mutually agreed day, to be granted within 28 days; or</p><p><strong>(c)</strong> where time off in lieu is not agreed or does not occur within 28 days, an additional day’s ordinary pay; or</p><p><strong>(d)</strong> an additional day’s annual leave which will not attract leave loading.</p><p><strong>99.8</strong> Mandatory Training</p><p><strong>(a)</strong> Any education or training deemed compulsory or mandatory by the Employer will occur within an Employee&#39;s paid time, and overtime applies where it would otherwise apply. No deduction will be made to an Employee&#39;s annual professional development leave for mandatory training.</p><p><strong>99.9</strong> Staff Replacement All absences resulting from approved leave under clause 99 (professional development leave) will be back-filled in clinical areas where that Employee would ordinarily have a patient allocation.</p>',37)])])}const g=o(r,[["render",s]]);export{c as __pageData,g as default};
